```
func navigateToSettings(withNextStep: Step? = nil) -> FlowContributors {
    let settingsFlow = SettingsFlow()
    
    Flows.use(settingsFlow, when: .ready) { [weak rootViewController] root in
      rootViewController?.present(root, animated: true, completion: {
        // The only way currently to process next step in case of deeplink is as follows
        // This needs to be refactored once we have a better solution on how to handle multiple flows
        if let nextStep = withNextStep {
          settingsFlow.stepper.steps.accept(nextStep)
        }
      })
    }

    return .one(flowContributor: .contribute(withNextPresentable: settingsFlow, withNextStepper: settingsFlow.stepper))
